/**
 * Theme colors — single source of truth for the entire app UI.
 *
 * Inspired by gemini-cli's dark theme: soft accent colors on a near-black
 * base, with input/message backgrounds generated by interpolating between
 * the terminal background and a mid-gray. This produces a subtle, layered
 * look instead of a flat or overly saturated palette.
 *
 * Usage:
 * ```tsx
 * import { COLORS, BG } from "../theme/colors.js";
 *
 * <Text color={COLORS.primary}>Active</Text>
 * <Text color={COLORS.muted} dimColor>Secondary</Text>
 * <HalfLinePaddedBox backgroundColor={BG.input}>...</HalfLinePaddedBox>
 * ```
 */

// ============================================================================
// Color Utilities
// ============================================================================

function hexToRgb(hex: string): [number, number, number] {
  const n = parseInt(hex.slice(1), 16);
  return [(n >> 16) & 255, (n >> 8) & 255, n & 255];
}

function rgbToHex(r: number, g: number, b: number): string {
  return "#" + ((1 << 24) | (r << 16) | (g << 8) | b).toString(16).slice(1);
}

/**
 * Linearly interpolate between two hex colors.
 * @param color1 - First hex color (e.g. "#000000")
 * @param color2 - Second hex color (e.g. "#8B949E")
 * @param factor - Blend factor: 0 = color1, 1 = color2
 */
export function interpolateColor(color1: string, color2: string, factor: number): string {
  const f = Math.max(0, Math.min(1, factor));
  const [r1, g1, b1] = hexToRgb(color1);
  const [r2, g2, b2] = hexToRgb(color2);
  return rgbToHex(Math.round(r1 + (r2 - r1) * f), Math.round(g1 + (g2 - g1) * f), Math.round(b1 + (b2 - b1) * f));
}

// ============================================================================
// Brand Gradient (Header logo only)
// ============================================================================

export const GRADIENT = {
  cyan: "#00D4FF",
  purple: "#7B61FF",
  pink: "#FF6B9D",
} as const;

// ============================================================================
// Base Palette
// ============================================================================

/**
 * Terminal base background. Most users run on a near-black terminal.
 * Background colors for input/messages are interpolated from this.
 */
const TERMINAL_BG = "#0D0D0F";
/** Mid-gray used for interpolating subtle background tints. */
const GRAY = "#8B949E";

// ============================================================================
// Semantic Colors
// ============================================================================

export const COLORS = {
  /** Primary — bright blue. Active state, titles, emphasis, links. */
  primary: "#58A6FF",
  /** Accent — purple. Inline code, special tags, user prefix. */
  accent: "#BC8CFF",
  /** Success — green. Completed, approved, ✓. */
  success: "#3FB950",
  /** Warning — amber. Waiting, approval needed, ?. */
  warning: "#E3B341",
  /** Danger — red. Errors, denied, ✗. */
  danger: "#F85149",
  /** Muted — gray. Secondary text, placeholders, dim info. */
  muted: "#8B949E",
  /** Text — light gray-white. Primary text content. */
  text: "#E6EDF3",
} as const;

// ============================================================================
// Background Colors
// ============================================================================

export const BG = {
  /**
   * Input box background — terminal black blended ~15% toward gray.
   * Subtle enough to distinguish from the main background without
   * being a heavy color block.
   */
  input: interpolateColor(TERMINAL_BG, GRAY, 0.15),
  /**
   * User message background — same family as input but slightly lighter
   * (~20%) so user messages stand out marginally from the input prompt.
   */
  message: interpolateColor(TERMINAL_BG, GRAY, 0.2),
  /** Default border / divider color — dark gray blended ~25% toward gray. */
  border: interpolateColor(TERMINAL_BG, GRAY, 0.25),
  /** Border for approved state */
  borderSuccess: COLORS.success,
  /** Border for denied state */
  borderDanger: COLORS.danger,
  /** File tree row — keyboard cursor (primary tint). */
  rowCursor: interpolateColor(TERMINAL_BG, COLORS.primary, 0.32),
  /** File tree row — open preview file (accent tint). */
  rowSelected: interpolateColor(TERMINAL_BG, COLORS.accent, 0.26),
} as const;
